    #[test]
    fn wrap_line_short() {
        let segments = wrap_line("hello", 20);
        assert_eq!(segments, vec![(0, 5)]);
    }

    #[test]
    fn wrap_line_exact_width() {
        let segments = wrap_line("hello", 5);
        assert_eq!(segments, vec![(0, 5)]);
    }

    #[test]
    fn wrap_line_over_width() {
        // "hello world" = 11 chars, wrap at 5
        // Segments: "hello" (0-5), " worl" (5-10), "d" (10-11)
        let segments = wrap_line("hello world", 5);
        assert_eq!(segments.len(), 3);
        assert_eq!(segments[0], (0, 5));
        assert_eq!(segments[1], (5, 10));
        assert_eq!(segments[2], (10, 11));
    }

    #[test]
    fn wrap_line_empty() {
        let segments = wrap_line("", 10);
        assert_eq!(segments, vec![(0, 0)]);
    }

    #[test]
    fn wrap_line_zero_width() {
        let segments = wrap_line("hello", 0);
        assert!(segments.is_empty());
    }

    #[test]
    fn wrap_line_wide_chars() {
        // "你好" = 2 chars, each width 2 = 4 display cols
        let segments = wrap_line("你好", 3);
        assert_eq!(segments.len(), 2);
        assert_eq!(segments[0], (0, 3)); // "你" (width 2, fits in 3)
        assert_eq!(segments[1], (3, 6)); // "好" (width 2, new segment)
    }

    #[test]
    fn wrap_line_wide_chars_fit() {
        let segments = wrap_line("你好", 4);
        assert_eq!(segments, vec![(0, 6)]);
    }

    #[test]
    fn wrap_line_three_segments() {
        // "abc def ghi" = 11 chars, wrap at 4
        // Segments: "abc " (0-4), "def " (4-8), "ghi" (8-11)
        let segments = wrap_line("abc def ghi", 4);
        assert_eq!(segments.len(), 3);
        assert_eq!(segments[0], (0, 4)); // "abc "
        assert_eq!(segments[1], (4, 8)); // "def "
        assert_eq!(segments[2], (8, 11)); // "ghi"
    }

    #[test]
    fn wrap_line_segments_are_char_boundaries() {
        // "héllo" = h(1) é(1) l(1) l(1) o(1) = 5 display cols, 6 bytes
        let segments = wrap_line("héllo", 3);
        assert_eq!(segments.len(), 2);
        // Verify segments don't split é (2-byte char)
        for &(start, end) in &segments {
            // Each segment should be valid UTF-8
            let _seg: &str = &"héllo"[start..end];
        }
    }

