    #[test]
    fn build_visual_lines_single_short_line() {
        let lines = build_visual_lines("hello", 20);
        assert_eq!(lines, vec![(0, 0, 5)]);
    }

    #[test]
    fn build_visual_lines_multiline() {
        let lines = build_visual_lines("abc\ndef", 20);
        assert_eq!(lines.len(), 2);
        assert_eq!(lines[0], (0, 0, 3));
        assert_eq!(lines[1], (1, 0, 3));
    }

    #[test]
    fn build_visual_lines_wraps_long_line() {
        let input = "short\nthis is a very long line that needs wrapping";
        let lines = build_visual_lines(input, 10);
        // Line 0: "short" → 1 visual line
        // Line 1: long → multiple visual lines
        assert_eq!(lines[0].0, 0); // logical line 0
        assert_eq!(lines[1].0, 1); // logical line 1
        assert!(lines.len() > 2); // at least 3 visual lines total
    }

