    // -----------------------------------------------------------------------
    // Regression: cursor_visual_pos must handle mid-char positions gracefully
    // -----------------------------------------------------------------------

    #[test]
    fn cursor_visual_pos_mid_char_does_not_panic() {
        // Simulate cursor_down landing inside a multi-byte character.
        // "a─" = a(1) + ─(3) = 4 bytes. Byte 3 is inside ─ (bytes 1..4).
        // This should NOT panic — should round down to byte 1 (after 'a').
        let (vl, vc) = cursor_visual_pos("a─", 3, 10);
        // Rounds to byte 1, so vis_col = width("a") = 1
        assert_eq!(vl, 0);
        assert_eq!(vc, 1);
    }

    #[test]
    fn cursor_visual_pos_multiline_mid_char_does_not_panic() {
        // "hello\na─" — cursor at byte 6+3=9 which is inside ─ in line 1.
        // Line 1: "a─", col_in_line = 3 (inside ─ at bytes 1..4).
        // Should round down to byte 1 (after 'a').
        let (vl, vc) = cursor_visual_pos("hello\na─", 9, 20);
        // Line 0 = 1 visual line. Line 1 = 1 visual line. vl = 1.
        // Rounds to byte 1, vis_col = width("a") = 1
        assert_eq!(vl, 1);
        assert_eq!(vc, 1);
    }

    #[test]
    fn cursor_visual_pos_box_drawing_paste() {
        // Reproduce exact panic scenario: pasted box-drawing characters
        // "┌────┐" = 7 bytes (┌(3) + ─(3) + ─(3) + ─(3) + ┐(3) = 15 bytes)
        // Cursor at byte 3 (start of second ─). This IS a boundary, should work fine.
        let (vl, vc) = cursor_visual_pos("┌────┐", 3, 20);
        assert_eq!(vl, 0);
        // ┌ has width 1, so vis_col = 1
        assert_eq!(vc, 1);
    }

    #[test]
    fn cursor_visual_pos_box_drawing_mid_char() {
        // "┌────┐" — cursor at byte 2 (inside ─ at bytes 0..3).
        // Should round down to 0.
        let (vl, vc) = cursor_visual_pos("┌────┐", 2, 20);
        assert_eq!(vl, 0);
        assert_eq!(vc, 0);
    }

