    #[test]
    fn last_char_boundary_ascii() {
        assert_eq!(last_char_boundary("hello", 0), 0);
        assert_eq!(last_char_boundary("hello", 1), 1);
        assert_eq!(last_char_boundary("hello", 5), 5);
        assert_eq!(last_char_boundary("hello", 100), 5); // clamped
    }

    #[test]
    fn last_char_boundary_mid_multibyte() {
        // "a─" = a(1) + ─(3) = 4 bytes
        assert_eq!(last_char_boundary("a─", 0), 0);
        assert_eq!(last_char_boundary("a─", 1), 1); // after 'a'
        assert_eq!(last_char_boundary("a─", 2), 1); // inside ─, rounds to 1
        assert_eq!(last_char_boundary("a─", 3), 1); // inside ─, rounds to 1
        assert_eq!(last_char_boundary("a─", 4), 4); // end
    }

    #[test]
    fn last_char_boundary_emoji() {
        // "a😀b" = a(1) + 😀(4) + b(1) = 6 bytes
        assert_eq!(last_char_boundary("a😀b", 0), 0);
        assert_eq!(last_char_boundary("a😀b", 1), 1); // after 'a'
        assert_eq!(last_char_boundary("a😀b", 2), 1); // inside 😀, rounds to 1
        assert_eq!(last_char_boundary("a😀b", 3), 1); // inside 😀, rounds to 1
        assert_eq!(last_char_boundary("a😀b", 4), 1); // inside 😀, rounds to 1
        assert_eq!(last_char_boundary("a😀b", 5), 5); // after 😀
        assert_eq!(last_char_boundary("a😀b", 6), 6); // end
    }

    #[test]
    fn last_char_boundary_empty() {
        assert_eq!(last_char_boundary("", 0), 0);
        assert_eq!(last_char_boundary("", 5), 0);
    }
